import { useState } from 'react';

function Members({ users, setUsers, goBack }) {
  const [search, setSearch] = useState('');
  const [editId, setEditId] = useState(null);
  const [editGrade, setEditGrade] = useState('');

  const grades = ['일반', 'VIP', '블랙리스트', '관리자'];

  const filteredUsers = users.filter((u) =>
    u.name.includes(search) || u.email.includes(search)
  );

  const handleGradeEdit = (index) => {
    setEditId(index);
    setEditGrade(users[index].grade || '일반');
  };

  const handleGradeSave = (index) => {
    setUsers(users.map((u, i) =>
      i === index ? { ...u, grade: editGrade } : u
    ));
    setEditId(null);
  };

  const handleDelete = (index) => {
    if (users[index].email === 'admin@srmart.com') {
      alert('관리자 계정은 삭제할 수 없어요!');
      return;
    }
    if (window.confirm(users[index].name + '님을 삭제할까요?')) {
      setUsers(users.filter((_, i) => i !== index));
    }
  };

  const gradeColor = (grade) => {
    if (grade === 'VIP') return { bg: '#fff3e0', color: '#e65100' };
    if (grade === '블랙리스트') return { bg: '#ffebee', color: '#c62828' };
    if (grade === '관리자') return { bg: '#e8f5e9', color: '#2e7d32' };
    return { bg: '#f5f5f5', color: '#666' };
  };

  return (
    <div style={{ padding: '32px', maxWidth: '900px', margin: '0 auto' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '24px' }}>
        <button onClick={goBack} style={{ padding: '8px 16px', background: '#f1f8e9', color: '#2e7d32', border: '1px solid #c8e6c9', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' }}>
          ← 뒤로
        </button>
        <h2 style={{ margin: 0, color: '#1b5e20' }}>👥 회원 관리</h2>
      </div>

      {/* 통계 */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px', marginBottom: '24px' }}>
        {[
          { label: '전체', value: users.length, color: '#e8f5e9', text: '#2e7d32' },
          { label: 'VIP', value: users.filter((u) => u.grade === 'VIP').length, color: '#fff3e0', text: '#e65100' },
          { label: '블랙리스트', value: users.filter((u) => u.grade === '블랙리스트').length, color: '#ffebee', text: '#c62828' },
          { label: '일반', value: users.filter((u) => !u.grade || u.grade === '일반').length, color: '#f5f5f5', text: '#666' },
        ].map((stat) => (
          <div key={stat.label} style={{ background: stat.color, borderRadius: '12px', padding: '16px', textAlign: 'center' }}>
            <p style={{ fontSize: '13px', color: '#888', margin: '0 0 4px' }}>{stat.label}</p>
            <p style={{ fontSize: '24px', fontWeight: 'bold', margin: 0, color: stat.text }}>{stat.value}명</p>
          </div>
        ))}
      </div>

      {/* 검색 */}
      <div style={{ marginBottom: '16px' }}>
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="이름 또는 이메일로 검색"
          style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #c8e6c9', fontSize: '14px', boxSizing: 'border-box' }}
        />
      </div>

      {/* 회원 목록 */}
      <div style={{ background: 'white', borderRadius: '12px', border: '1px solid #e0e0e0', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: '#2e7d32', color: 'white' }}>
              <th style={{ padding: '14px 16px', textAlign: 'left' }}>이름</th>
              <th style={{ padding: '14px 16px', textAlign: 'left' }}>이메일</th>
              <th style={{ padding: '14px 16px', textAlign: 'center' }}>등급</th>
              <th style={{ padding: '14px 16px', textAlign: 'center' }}>관리</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.length === 0 ? (
              <tr>
                <td colSpan="4" style={{ padding: '40px', textAlign: 'center', color: '#888' }}>검색 결과가 없어요!</td>
              </tr>
            ) : (
              filteredUsers.map((user, index) => (
                <tr key={user.email} style={{ borderBottom: '1px solid #e0e0e0' }}>
                  <td style={{ padding: '14px 16px', fontWeight: '500' }}>{user.name}</td>
                  <td style={{ padding: '14px 16px', fontSize: '13px', color: '#666' }}>{user.email}</td>
                  <td style={{ padding: '14px 16px', textAlign: 'center' }}>
                    {editId === index ? (
                      <div style={{ display: 'flex', gap: '6px', justifyContent: 'center' }}>
                        <select
                          value={editGrade}
                          onChange={(e) => setEditGrade(e.target.value)}
                          style={{ padding: '6px', borderRadius: '6px', border: '1px solid #c8e6c9', fontSize: '13px' }}
                        >
                          {grades.map((g) => (
                            <option key={g} value={g}>{g}</option>
                          ))}
                        </select>
                        <button onClick={() => handleGradeSave(index)} style={{ padding: '6px 12px', background: '#2e7d32', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '12px' }}>저장</button>
                        <button onClick={() => setEditId(null)} style={{ padding: '6px 12px', background: '#888', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '12px' }}>취소</button>
                      </div>
                    ) : (
                      <span style={{ background: gradeColor(user.grade || '일반').bg, color: gradeColor(user.grade || '일반').color, padding: '4px 12px', borderRadius: '20px', fontSize: '13px', fontWeight: 'bold' }}>
                        {user.grade || '일반'}
                      </span>
                    )}
                  </td>
                  <td style={{ padding: '14px 16px', textAlign: 'center' }}>
                    <div style={{ display: 'flex', gap: '8px', justifyContent: 'center' }}>
                      <button onClick={() => handleGradeEdit(index)} style={{ padding: '7px 14px', background: '#1976d2', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '13px' }}>✏️ 등급</button>
                      <button onClick={() => handleDelete(index)} style={{ padding: '7px 14px', background: '#e53935', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '13px' }}>🗑️ 삭제</button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Members;
